function isEmpty(source) {
    // Checks for null, undefined, not an array, or empty array
    return !Array.isArray(source) || source.length === 0;
}
var resultArray = [];
var dbString = source;
if(!isEmpty(source)){
	for(var i = 0; i < source.length; i++){
		try{
		var appName;
		var sourceAppId = source[i].applicationId;
		//query to get appName
		var appNameResponse = openidm.query(
			"managed/alpha_kyid_businessapplication",{
				 "_queryFilter": '_id eq "' + sourceAppId + '"'
			},
			["name"]
		);
		if (appNameResponse.result && appNameResponse.result.length == 1) {
		   	appName = appNameResponse.result[0].name;
			logger.error("appName : "+appName);
		}else{
			appName = "";
			logger.error("appName : "+appName);
		}
		//role
		if(!source[i].roleId == null || !source[i].roleId == ""){
			var sourceRoleId = source[i].roleId;
			logger.error("sourceRoleId from source content : "+sourceRoleId);
			var roleResponse = openidm.query(
			"managed/alpha_role",{
				 "_queryFilter": '_id eq "' + sourceRoleId + '"'
			},
			["businessRoleId"]
			);
			logger.error("App Response: " + JSON.stringify(roleResponse));

			if (roleResponse.result && roleResponse.result.length == 1) {
				businessRoleId = roleResponse.result[0].businessRoleId;
				logger.error("businessRoleId : "+businessRoleId);
			}else{
				businessRoleId = "";
				logger.error("businessRoleId : "+businessRoleId);
			}
		}else{
			var businessRoleId = "";
			logger.error("businessRoleId from source content : "+businessRoleId);
		}

		resultArray.push(appName + ',' + businessRoleId );
		logger.error("Result Array 1: " + resultArray);

		if (resultArray.length == 1) {
			// Remove comma if only one element
			resultString = resultArray[0].replace(/,$/, '');

		} else {
			resultString = resultArray.join('|');
		}

		logger.error("Result Array 2: " + resultString);
		resultString;

		}catch(error){
		  logger.error("Exception : "+error);
		}
	}


}else{
	null;
}

